#include "primer/hyperloglog.h"

#include <algorithm>
#include <cmath>

namespace bustub {

template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : cardinality_(0), n_bits_(n_bits) {
  // Handle edge cases for invalid n_bits
  if (n_bits <= 0) {
    n_bits_ = 0;
    m_ = 0;
  } else {
    m_ = 1UL << n_bits;
    registers_.assign(m_, 0);
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  return std::bitset<BITSET_CAPACITY>(hash);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find the position of the leftmost 1 bit (counting from right, starting at 1)
  // If no 1 bit is found, return 0
  for (int i = BITSET_CAPACITY - 1; i >= 0; --i) {
    if (bset[i]) {
      return BITSET_CAPACITY - i;
    }
  }
  return 0;
}

template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ <= 0) {
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  hash_t hash = CalculateHash(val);
  std::bitset<BITSET_CAPACITY> bset = ComputeBinary(hash);

  // Get the first n_bits as the bucket index
  uint64_t bucket = hash & ((1UL << n_bits_) - 1);

  // Get the remaining bits after the first n_bits
  hash_t w = hash >> n_bits_;
  std::bitset<BITSET_CAPACITY> w_bits = std::bitset<BITSET_CAPACITY>(w);

  // Find position of leftmost one in the remaining bits
  uint64_t position = PositionOfLeftmostOne(w_bits) + 1;

  // Update the register with the maximum position
  registers_[bucket] = std::max(registers_[bucket], static_cast<uint8_t>(position));
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  if (n_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Calculate the raw estimate using the formula:
