template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits)
    : cardinality_(0), n_leading_bits_(n_leading_bits) {
  if (n_leading_bits <= 0) {
    n_leading_bits_ = 0;
    num_buckets_ = 1;
  } else {
    num_buckets_ = 1UL << n_leading_bits;
  }
  dense_bucket_.assign(num_buckets_, std::bitset<DENSE_BUCKET_SIZE>(0));
}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  std::lock_guard<std::mutex> lock(mutex_);

  hash_t hash = CalculateHash(val);

  // Extract bucket index from leading bits
  uint16_t bucket_index = 0;
  if (n_leading_bits_ > 0) {
    bucket_index = (hash >> (64 - n_leading_bits_)) & ((1UL << n_leading_bits_) - 1);
  }

  // Get the remaining bits after bucket extraction
  hash_t w = hash;
  if (n_leading_bits_ > 0) {
    w = (hash << n_leading_bits_) & ((1ULL << 64) - 1);
  }

  // Count leading zeros in w to get the position
  uint64_t position = 0;
  if (w == 0) {
    position = 64 - n_leading_bits_ + 1;
  } else {
    // Count leading zeros
    int leading_zeros = 0;
    for (int i = 63 - n_leading_bits_; i >= 0; --i) {
      if ((w >> i) & 1) {
        break;
      }
      leading_zeros++;
    }
    position = leading_zeros + 1;
  }

  // Update dense and overflow buckets
  std::bitset<DENSE_BUCKET_SIZE> current_dense = dense_bucket_[bucket_index];
  uint64_t current_value = current_dense.to_ullong();

  if (position <= 15) {
    // Store in dense bucket
    std::bitset<DENSE_BUCKET_SIZE> new_dense(std::max(current_value, position));
    dense_bucket_[bucket_index] = new_dense;
    // Clear overflow for this bucket if we're using it for dense
    if (position >= 15) {
      if (overflow_bucket_.find(bucket_index) == overflow_bucket_.end()) {
        overflow_bucket_[bucket_index] = std::bitset<OVERFLOW_BUCKET_SIZE>(0);
      }
    }
  } else {
    // Store in overflow bucket
    dense_bucket_[bucket_index] = std::bitset<DENSE_BUCKET_SIZE>(15);
    uint64_t overflow_value = position - 15;
    if (overflow_bucket_.find(bucket_index) == overflow_bucket_.end()) {
      overflow_bucket_[bucket_index] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_value);
    } else {
      overflow_bucket_[bucket_index] =
          std::bitset<OVERFLOW_BUCKET_SIZE>(
              std::max(overflow_bucket_[bucket_index].to_ullong(), overflow_value));
    }
  }
}

template <typename T>
