#include "primer/hyperloglog_presto.h"

#include <algorithm>
#include <cmath>

namespace bustub {

template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits)
    : cardinality_(0), n_leading_bits_(n_leading_bits) {
  if (n_leading_bits <= 0) {
    n_leading_bits_ = 0;
    num_buckets_ = 1;
  } else {
    num_buckets_ = 1UL << n_leading_bits;
  }
  dense_bucket_.assign(num_buckets_, std::bitset<DENSE_BUCKET_SIZE>(0));
}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  std::lock_guard<std::mutex> lock(mutex_);

  hash_t hash = CalculateHash(val);

  // Extract bucket index from leading bits
  uint16_t bucket_index = 0;
  if (n_leading_bits_ > 0) {
    bucket_index = (hash >> (64 - n_leading_bits_)) & ((1UL << n_leading_bits_) - 1);
  }

  // Find the position of the leading 1 bit (bit index from right, 0-63)
  uint64_t position = 0;
  if (hash == 0) {
    position = 0;
  } else {
    // Find the highest bit set
    for (int i = 63; i >= 0; --i) {
      if ((hash >> i) & 1) {
        position = i;
        break;
      }
    }
  }

  // Store position in dense and overflow buckets
  // dense = position & 0xF (lower 4 bits)
  // overflow = position >> 4 (upper bits)
  uint64_t dense_value = position & 0xF;
  uint64_t overflow_value = position >> 4;

  // Update dense bucket with maximum
  dense_bucket_[bucket_index] =
      std::bitset<DENSE_BUCKET_SIZE>(std::max(dense_bucket_[bucket_index].to_ullong(), dense_value));

  // Update overflow bucket with maximum
  if (overflow_bucket_.find(bucket_index) == overflow_bucket_.end()) {
    overflow_bucket_[bucket_index] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_value);
  } else {
    overflow_bucket_[bucket_index] =
        std::bitset<OVERFLOW_BUCKET_SIZE>(
            std::max(overflow_bucket_[bucket_index].to_ullong(), overflow_value));
  }
}

template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  std::lock_guard<std::mutex> lock(mutex_);

  if (num_buckets_ == 0) {
    cardinality_ = 0;
    return;
  }

  // Calculate raw estimate
  double sum = 0.0;
  for (size_t i = 0; i < num_buckets_; ++i) {
    uint64_t position = dense_bucket_[i].to_ullong();
    if (overflow_bucket_.find(i) != overflow_bucket_.end()) {
      position |= (overflow_bucket_[i].to_ullong() << 4);
    }
    // For position p, contribution is 2^(-(p+1)) since position is bit index
    sum += std::pow(2.0, -static_cast<double>(position + 1));
  }

  double raw_estimate = CONSTANT * num_buckets_ * num_buckets_ / sum;

  // Apply bias correction
  if (raw_estimate <= 2.5 * num_buckets_) {
    size_t empty_count = 0;
    for (size_t i = 0; i < num_buckets_; ++i) {
      if (dense_bucket_[i].to_ullong() == 0 &&
          overflow_bucket_.find(i) == overflow_bucket_.end()) {
        empty_count++;
      }
    }
    if (empty_count != 0) {
      cardinality_ = num_buckets_ * std::log(static_cast<double>(num_buckets_) / empty_count);
    } else {
      cardinality_ = static_cast<uint64_t>(raw_estimate);
    }
  } else if (raw_estimate <= (1.0 / 30.0) * (1ULL << 32)) {
    cardinality_ = static_cast<uint64_t>(raw_estimate);
  } else {
    cardinality_ = static_cast<uint64_t>(-(1ULL << 32) * std::log(1.0 - raw_estimate / (1ULL << 32)));
  }
}

template class HyperLogLogPresto<int64_t>;
template class HyperLogLogPresto<std::string>;
}  // namespace bustub

